async (params, browser) => {
  // Open user profile
  await browser.open(`https://x.com/${params.username}`)

  // Wait for page content
  await browser.waitForSelector('[data-testid=\'UserName\']', 15000)

  // Let page settle
  await browser.wait(1000)

  // Follow user (skip if already following)
  const result = await browser.evaluate(`const followBtn = document.querySelector('[data-testid$="-follow"]'); const unfollowBtn = document.querySelector('[data-testid$="-unfollow"]'); if (unfollowBtn) return { already_following: true, message: 'Already following this user' }; if (followBtn) { followBtn.click(); return { success: true, message: 'Followed user' }; } return { success: false, message: 'Follow button not found' }`)

  return result
}
